import React, { useEffect, useMemo, useState } from "react";
import { Link } from "react-router-dom";
import Navbar from "../components/Navbar";
import Footer from "../components/Footer";
import { getMatches } from "../services/api";

function Matches() {
  const [matches, setMatches] = useState([]);
  const [error, setError] = useState("");
  const [search, setSearch] = useState("");

  useEffect(() => {
    const fetchMatches = async () => {
      try {
        const data = await getMatches();
        setMatches(data);
      } catch (err) {
        setError(err.message);
      }
    };

    fetchMatches();
  }, []);

  const filteredMatches = useMemo(() => {
    return matches.filter(
      (match) =>
        match.title?.toLowerCase().includes(search.toLowerCase()) ||
        match.location?.toLowerCase().includes(search.toLowerCase())
    );
  }, [matches, search]);

  return (
    <div>
      <Navbar />

      <div className="container page-section">
        <div className="section-head">
          <div>
            <h1 className="section-title">Tìm trận bóng</h1>
            <p className="section-subtitle">
              Xem các trận đang mở đăng ký và tham gia cùng cộng đồng bóng đá.
            </p>
          </div>
        </div>

        <div className="filter-bar">
          <input
            type="text"
            placeholder="Tìm theo tên trận hoặc địa điểm..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
          <button className="btn-primary">Tìm kiếm</button>
        </div>

        {error && <p className="error-text">{error}</p>}

        {!error && filteredMatches.length === 0 && (
          <div className="empty-box">Hiện chưa có trận phù hợp.</div>
        )}

        <div className="fields-grid">
          {filteredMatches.map((match) => (
            <div key={match.id} className="match-card">
              <div className="match-top">
                <span className="match-badge">Đang mở đăng ký</span>
                <span className="match-capacity">
                  Tối đa {match.max_players} người
                </span>
              </div>

              <h3 className="match-title">{match.title}</h3>

              <p className="match-info">
                <strong>Địa điểm:</strong> {match.location}
              </p>

              <p className="match-info">
                <strong>Thời gian:</strong> {match.time}
              </p>

              <Link to={`/matches/${match.id}`}>
                <button className="btn-book" style={{ width: "100%" }}>
                  Xem chi tiết
                </button>
              </Link>
            </div>
          ))}
        </div>
      </div>

      <Footer />
    </div>
  );
}

export default Matches;
